    return '<div class="cf-success">' + '<div class="cf-success-ring">✓</div>' + '<h2>' + (f.publishMode === 'draft' ? 'Draft saved' : f.publishMode === 'schedule' ? 'Scheduled' : f.publishMode === 'campaign' ? 'Added to campaign' : 'Live') + '</h2>' + '<p style="color:var(--muted);margin-bottom:8px;">' + modeLabel + '</p>' + '<p class="cf-success-stat">Created in ~' + elapsed + 's · ' + f.modality + ' · ' + f.format + '</p>' + '<p style="font-size:12px;color:var(--muted);margin-top:8px;">Saved to Library with rationale, brief, and publish state.</p>' + '<div style="display:flex;gap:10px;justify-content:center;margin-top:24px;">' + '<button class="btn btn-primary" onclick="cfReset()">Create another</button>' + '<button class="btn btn-outline" onclick="cfOpenLibrary()">View library</button>' + '</div></div>';
