  function cfStatusClass(status) {
    var map = {
      Draft: 'pill-muted',
      Published: 'pill-green',
      Scheduled: 'pill-indigo',
      'In Campaign': 'pill-amber'
    };
    return map[status] || 'pill-muted';
  }
  function cfEnsureStats(item) {
    if (!item.stats) {
      var base = 0;
      for (var i = 0; i < item.id.length; i++) base += item.id.charCodeAt(i) * (i + 1);
      var seed = base * 97 % 997;
      item.stats = {
        views: 1100 + seed * 7,
        likes: 70 + seed % 280,
        comments: 4 + seed % 38,
        shares: 2 + seed % 22
      };
    }
    return item.stats;
  }
  function cfFmtNum(n) {
    if (n >= 1000) return (n / 1000).toFixed(1).replace(/\.0$/, '') + 'k';
    return '' + n;
  }
  function cfStatsRow(item, compact) {
    var s = cfEnsureStats(item);
    var cls = compact ? 'cf-lib-stats' : 'cf-lib-stats cf-lib-stats-lg';
    return '<div class="' + cls + '">' + '<span class="cf-lib-stat">\uD83D\uDC41 ' + cfFmtNum(s.views) + '</span>' + '<span class="cf-lib-stat">\u2764\uFE0F ' + cfFmtNum(s.likes) + '</span>' + '<span class="cf-lib-stat">\uD83D\uDCAC ' + cfFmtNum(s.comments) + '</span>' + '<span class="cf-lib-stat">\u21AA ' + cfFmtNum(s.shares) + '</span>' + '</div>';
  }
  function cfFormatSchedule(dateStr, timeStr) {
    if (!dateStr) return '';
    var parts = dateStr.split('-');
    if (parts.length !== 3) return '';
    var months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    var label = months[parseInt(parts[1], 10) - 1] + ' ' + parseInt(parts[2], 10) + ', ' + parts[0];
    if (timeStr) {
      var tp = timeStr.split(':');
      var h = parseInt(tp[0], 10);
      var m = tp[1] || '00';
      var ampm = h >= 12 ? 'PM' : 'AM';
      var h12 = h % 12;
      if (h12 === 0) h12 = 12;
      label += ' \u00B7 ' + h12 + ':' + m + ' ' + ampm;
    }
    return label;
  }
